sql.where:
cr.deleted = 0

    AND cr.record_code LIKE CONCAT('%', #{query.recordCode}, '%')


    AND cr.check_name LIKE CONCAT('%', #{query.checkName}, '%')


    AND cr.check_type = #{query.checkType}


    AND cr.status = #{query.status}


    AND cr.template_id = #{query.templateId}


    AND cr.rating_template_id = #{query.ratingTemplateId}


    AND cr.check_date >= #{query.checkDateStart}


    AND cr.check_date <= #{query.checkDateEnd}


    AND cr.created_by = #{query.createdBy}

