SET status = #{status},
    updated_at = NOW()

    , submitted_at = NOW()
    , submitted_by = #{userId}


    , reviewed_at = NOW()
    , reviewed_by = #{userId}


    , published_at = NOW()
    , published_by = #{userId}


    , archived_at = NOW()
    , archived_by = #{userId}

WHERE deleted = 0
AND id IN

    #{id}

mapper.select:
SELECT cr.id, cr.record_code, cr.check_name, cr.check_date, cr.status, cr.total_classes, cr.total_items, cr.total_deduct, ct.template_name FROM check_records cr LEFT JOIN check_templates ct ON cr.template_id = ct.id AND ct.deleted = 0
cr.deleted = 0
AND cr.check_type = #{query.checkType}
AND cr.status = #{query.status}
LIMIT #{query.limit}
ORDER BY cr.check_date DESC
